import { ethers } from "ethers";
import fetch from "node-fetch";

const BASE_URL = process.env.HYPERLIQUID_TESTNET
  ? "https://api.hyperliquid-testnet.xyz"
  : "https://api.hyperliquid.xyz";

const address =
  process.env.HYPERLIQUID_ADDRESS ||
  (process.env.HYPERLIQUID_PRIVATE_KEY
    ? new ethers.Wallet(process.env.HYPERLIQUID_PRIVATE_KEY).address
    : null);

const wallet = process.env.HYPERLIQUID_PRIVATE_KEY
  ? new ethers.Wallet(process.env.HYPERLIQUID_PRIVATE_KEY)
  : null;

async function infoRequest(body) {
  const res = await fetch(`${BASE_URL}/info`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  return res.json();
}

async function signAndSend(action) {
  if (!wallet) throw new Error("Private key required for trading operations");

  const timestamp = Date.now();
  const phantomAgent = {
    source: "a",
    connectionId: ethers.id(JSON.stringify({ action, nonce: timestamp })),
  };

  const domain = {
    name: "Exchange",
    version: "1",
    chainId: 1337,
    verifyingContract: "0x0000000000000000000000000000000000000000",
  };

  const types = {
    Agent: [
      { name: "source", type: "string" },
      { name: "connectionId", type: "bytes32" },
    ],
  };

  const signature = await wallet.signTypedData(domain, types, phantomAgent);
  const { v, r, s } = ethers.Signature.from(signature);

  const payload = {
    action,
    nonce: timestamp,
    signature: { r, s, v },
  };

  const res = await fetch(`${BASE_URL}/exchange`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(payload),
  });
  return res.json();
}

async function getBalance() {
  if (!address) throw new Error("Address required");
  const data = await infoRequest({
    type: "clearinghouseState",
    user: address,
  });

  const equity = parseFloat(data.crossMarginSummary?.accountValue || 0);
  const available = parseFloat(
    data.crossMarginSummary?.withdrawable || data.withdrawable || 0
  );
  const marginUsed = parseFloat(
    data.crossMarginSummary?.totalMarginUsed || 0
  );

  return { equity, available, marginUsed, raw: data };
}

async function getPositions() {
  if (!address) throw new Error("Address required");
  const data = await infoRequest({
    type: "clearinghouseState",
    user: address,
  });

  const positions = (data.assetPositions || [])
    .filter((p) => parseFloat(p.position.szi) !== 0)
    .map((p) => ({
      coin: p.position.coin,
      size: parseFloat(p.position.szi),
      entryPrice: parseFloat(p.position.entryPx),
      value: parseFloat(p.position.positionValue),
      unrealizedPnl: parseFloat(p.position.unrealizedPnl),
      leverage: p.position.leverage,
    }));

  return positions;
}

async function getOrders() {
  if (!address) throw new Error("Address required");
  return infoRequest({ type: "openOrders", user: address });
}

async function getFills() {
  if (!address) throw new Error("Address required");
  return infoRequest({ type: "userFills", user: address });
}

async function getPrice(coin) {
  const mids = await infoRequest({ type: "allMids" });
  const price = mids[coin];
  if (!price) throw new Error(`Unknown coin: ${coin}`);
  return parseFloat(price);
}

async function getMeta() {
  return infoRequest({ type: "meta" });
}

async function getAssetIndex(coin) {
  const meta = await getMeta();
  const idx = meta.universe.findIndex((a) => a.name === coin);
  if (idx === -1) throw new Error(`Unknown coin: ${coin}`);
  return idx;
}

async function placeOrder(coin, isBuy, price, size, reduceOnly = false) {
  const assetIndex = await getAssetIndex(coin);
  const action = {
    type: "order",
    orders: [
      {
        a: assetIndex,
        b: isBuy,
        p: price.toString(),
        s: size.toString(),
        r: reduceOnly,
        t: { limit: { tif: "Gtc" } },
      },
    ],
    grouping: "na",
  };
  return signAndSend(action);
}

async function marketOrder(coin, isBuy, size) {
  const price = await getPrice(coin);
  const slippage = isBuy ? 1.05 : 0.95;
  const limitPrice = (price * slippage).toFixed(1);
  return placeOrder(coin, isBuy, limitPrice, size);
}

async function cancelOrder(coin, orderId) {
  const assetIndex = await getAssetIndex(coin);
  const action = {
    type: "cancel",
    cancels: [{ a: assetIndex, o: orderId }],
  };
  return signAndSend(action);
}

async function cancelAllOrders(coin) {
  let cancels = [];
  const orders = await getOrders();

  if (coin) {
    const assetIndex = await getAssetIndex(coin);
    cancels = orders
      .filter((o) => o.coin === coin)
      .map((o) => ({ a: assetIndex, o: o.oid }));
  } else {
    const meta = await getMeta();
    cancels = orders.map((o) => ({
      a: meta.universe.findIndex((a) => a.name === o.coin),
      o: o.oid,
    }));
  }

  if (cancels.length === 0) {
    return { status: "ok", message: "No orders to cancel" };
  }

  const action = { type: "cancel", cancels };
  return signAndSend(action);
}

