import { ethers } from "ethers";
import fetch from "node-fetch";

const BASE_URL = process.env.HYPERLIQUID_TESTNET
  ? "https://api.hyperliquid-testnet.xyz"
  : "https://api.hyperliquid.xyz";

const PRIVATE_KEY = process.env.HYPERLIQUID_PRIVATE_KEY;
const ADDRESS =
  process.env.HYPERLIQUID_ADDRESS ||
  (PRIVATE_KEY ? new ethers.Wallet(PRIVATE_KEY).address : null);

async function apiRequest(endpoint, body) {
  const response = await fetch(`${BASE_URL}${endpoint}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  return response.json();
}

async function signAndSend(action) {
  if (!PRIVATE_KEY) throw new Error("Private key required for trading");
  const wallet = new ethers.Wallet(PRIVATE_KEY);
  const timestamp = Date.now();

  const messageToSign = ethers.utils.arrayify(
    ethers.utils.keccak256(
      ethers.utils.toUtf8Bytes(JSON.stringify({ ...action, timestamp }))
    )
  );

  const signature = await wallet.signMessage(messageToSign);

  return apiRequest("/exchange", {
    action,
    signature,
    timestamp,
  });
}

async function getBalance(address) {
  const addr = address || ADDRESS;
  if (!addr) throw new Error("Address required");
  return apiRequest("/info", { type: "clearinghouseState", user: addr });
}

async function getPositions(address) {
  const data = await getBalance(address);
  return data.assetPositions || [];
}

async function getOpenOrders(address) {
  const addr = address || ADDRESS;
  if (!addr) throw new Error("Address required");
  return apiRequest("/info", { type: "openOrders", user: addr });
}

async function getFills(address) {
  const addr = address || ADDRESS;
  if (!addr) throw new Error("Address required");
  return apiRequest("/info", { type: "userFills", user: addr });
}

async function getMeta() {
  return apiRequest("/info", { type: "meta" });
}

async function getPrice(coin) {
  const mids = await apiRequest("/info", { type: "allMids" });
  return mids[coin] || null;
}

async function placeOrder(coin, isBuy, price, size) {
  const meta = await getMeta();
  const assetIndex = meta.universe.findIndex((a) => a.name === coin);
  if (assetIndex === -1) throw new Error(`Unknown coin: ${coin}`);

  const action = {
    type: "order",
    orders: [
      {
        a: assetIndex,
        b: isBuy,
        p: price.toString(),
        s: size.toString(),
        r: false,
        t: { limit: { tif: "Gtc" } },
      },
    ],
    grouping: "na",
  };

  return signAndSend(action);
}

async function marketOrder(coin, isBuy, size) {
  const price = await getPrice(coin);
  if (!price) throw new Error(`Cannot get price for ${coin}`);

  const slippage = isBuy ? 1.05 : 0.95;
  const limitPrice = (parseFloat(price) * slippage).toFixed(2);

  return placeOrder(coin, isBuy, limitPrice, size);
}

async function cancelOrder(coin, orderId) {
  const meta = await getMeta();
  const assetIndex = meta.universe.findIndex((a) => a.name === coin);
  if (assetIndex === -1) throw new Error(`Unknown coin: ${coin}`);

  const action = {
    type: "cancel",
    cancels: [{ a: assetIndex, o: parseInt(orderId) }],
  };

  return signAndSend(action);
}

async function cancelAllOrders(coin) {
  const orders = await getOpenOrders();
  if (!orders.length) return { message: "No open orders" };

  const meta = await getMeta();
  let cancels = orders.map((o) => ({
    a: meta.universe.findIndex((a) => a.name === o.coin),
    o: o.oid,
  }));

  if (coin) {
    cancels = cancels.filter(
      (c) => meta.universe[c.a]?.name === coin.toUpperCase()
    );
  }

  const action = { type: "cancel", cancels };
  return signAndSend(action);
}

const [, , command, ...args] = process.argv;

try {
  let result;
  switch (command) {
    case "balance":
      result = await getBalance(args[0]);
      break;
    case "positions":
      result = await getPositions(args[0]);
      break;
    case "orders":
      result = await getOpenOrders(args[0]);
      break;
    case "fills":
      result = await getFills(args[0]);
      break;
    case "meta":
      result = await getMeta();
      break;
    case "price":
      result = { coin: args[0], price: await getPrice(args[0]) };
      break;
    case "buy":
      result = await placeOrder(args[0], true, args[2], args[1]);
      break;
    case "sell":
      result = await placeOrder(args[0], false, args[2], args[1]);
      break;
    case "market-buy":
      result = await marketOrder(args[0], true, args[1]);
      break;
    case "market-sell":
      result = await marketOrder(args[0], false, args[1]);
      break;
    case "cancel":
      result = await cancelOrder(args[0], args[1]);
      break;
    case "cancel-all":
      result = await cancelAllOrders(args[0]);
      break;
    default:
      console.error(`Unknown command: ${command}`);
      process.exit(1);
  }
  console.log(JSON.stringify(result, null, 2));
} catch (e) {
  console.error(e.message);
  process.exit(1);
}
